import React, { useState, useEffect } from 'react';
import { authAPI, mongoAPI } from '../services/api';
import { Button, Select, Input, Textarea, Alert, PageHeader, Card, Badge, EmptyState } from '../components/ui';
import ResultsPanel from '../components/ui/ResultsPanel';
import { Leaf, Send, Sparkles } from 'lucide-react';
import './QueryPage.css';

const SAMPLE_QUESTIONS = [
  'Show top 10 customers by total spent',
  'Find all orders from the Asia Pacific region',
  'Which products have the most reviews?',
  'Show monthly revenue trend',
  'Find customers who have not ordered in 90 days',
];

export default function MongoPage() {
  const [connections, setConnections] = useState([]);
  const [selectedConn, setSelectedConn] = useState('');
  const [databases, setDatabases] = useState([]);
  const [collections, setCollections] = useState([]);
  const [dbName, setDbName] = useState('');
  const [collection, setCollection] = useState('');
  const [question, setQuestion] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [loadingDbs, setLoadingDbs] = useState(false);

  useEffect(() => {
    authAPI.connections()
      .then(r => {
        const mg = (r.data || []).filter(c => c.db_type === 'mongodb');
        setConnections(mg);
        if (mg.length) setSelectedConn(mg[0].id);
      }).catch(() => {});
  }, []);

  const conn = connections.find(c => c.id === Number(selectedConn) || c.id === selectedConn);

  useEffect(() => {
    if (!conn) return;
    setLoadingDbs(true);
    mongoAPI.listDbs(conn.connection_string)
      .then(r => { setDatabases(r.data?.databases || []); setDbName(''); setCollections([]); setCollection(''); })
      .catch(() => {})
      .finally(() => setLoadingDbs(false));
  }, [selectedConn]);

  useEffect(() => {
    if (!conn || !dbName) return;
    mongoAPI.listColls(conn.connection_string, dbName)
      .then(r => { setCollections(r.data?.collections || []); setCollection(''); })
      .catch(() => {});
  }, [dbName]);

  const runQuery = async () => {
    if (!question.trim())   return setError('Please enter a question.');
    if (!conn)              return setError('Please select a connection.');
    if (!dbName)            return setError('Please select a database.');
    if (!collection)        return setError('Please select a collection.');
    setLoading(true); setError(''); setResult(null);
    try {
      const { data } = await mongoAPI.nlQuery({
        mongo_uri: conn.connection_string,
        db_name: dbName,
        collection,
        question: question.trim(),
        limit: 100,
      });
      setResult(data);
    } catch (err) {
      setError(err.response?.data?.detail || 'Query failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="query-page fade-in">
      <PageHeader
        title="MongoDB Query"
        subtitle="Query your MongoDB collections with natural language"
        actions={<Badge color="green"><Leaf size={12}/> MongoDB</Badge>}
      />

      <div className="query-layout">
        <div className="query-input-col">
          <Card>
            <div className="query-form">
              {connections.length === 0 ? (
                <EmptyState
                  icon={<Leaf size={22}/>}
                  title="No MongoDB connections"
                  description="Add a MongoDB connection first to start querying."
                />
              ) : (
                <>
                  <Select label="Connection" value={selectedConn} onChange={e => setSelectedConn(e.target.value)}>
                    {connections.map(c => (
                      <option key={c.id} value={c.id}>{c.name || c.db_name || `Connection ${c.id}`}</option>
                    ))}
                  </Select>

                  <Select label="Database" value={dbName} onChange={e => setDbName(e.target.value)} disabled={loadingDbs || !databases.length}>
                    <option value="">{loadingDbs ? 'Loading…' : databases.length ? 'Select database' : 'No databases found'}</option>
                    {databases.map(d => <option key={d} value={d}>{d}</option>)}
                  </Select>

                  <Select label="Collection" value={collection} onChange={e => setCollection(e.target.value)} disabled={!collections.length}>
                    <option value="">{collections.length ? 'Select collection' : 'Select database first'}</option>
                    {collections.map(c => <option key={c} value={c}>{c}</option>)}
                  </Select>

                  <Textarea
                    label="Your Question"
                    value={question}
                    onChange={e => setQuestion(e.target.value)}
                    placeholder="e.g. Show top 10 customers by total spent"
                    rows={4}
                    onKeyDown={e => { if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) runQuery(); }}
                    hint="Press Ctrl+Enter to run"
                  />

                  {error && <Alert type="error" onClose={() => setError('')}>{error}</Alert>}

                  <Button onClick={runQuery} loading={loading} size="lg" icon={loading ? null : <Send size={15}/>} style={{ width: '100%' }}>
                    {loading ? 'Running query…' : 'Run Query'}
                  </Button>
                </>
              )}
            </div>
          </Card>

          <div className="sample-questions">
            <div className="sample-title"><Sparkles size={13}/> Sample questions</div>
            {SAMPLE_QUESTIONS.map(q => (
              <button key={q} className="sample-btn" onClick={() => setQuestion(q)}>{q}</button>
            ))}
          </div>
        </div>

        <div className="query-result-col">
          {loading && (
            <Card className="query-loading-card">
              <div className="query-loading">
                <div className="query-loading-spinner" />
                <div>
                  <div className="query-loading-title">Running AI pipeline…</div>
                  <div className="query-loading-sub">MongoDB Schema → Gemini → Query → EDA</div>
                </div>
              </div>
            </Card>
          )}
          {!loading && result && <ResultsPanel result={result} />}
          {!loading && !result && (
            <div className="query-empty">
              <div className="query-empty-icon"><Leaf size={32}/></div>
              <div className="query-empty-title">Ready to query</div>
              <div className="query-empty-sub">Select a collection and ask your question</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
